 (usually "connection refused: <reason>") and writing another one is
 unnecessary clutter. */

 if (!smtp_start_session())
 {
 mac_smtp_fflush();
 search_tidyup();
 _exit(EXIT_SUCCESS);
 }

 for (;;)
