{
 int PossibleID_Length = 0;
 binary PossibleIdNSize[16];
 int PossibleSizeLength;
 uint64 SizeUnknown;
 int ReadIndex = 0; // trick for the algo, start index at 0
 uint32 ReadSize = 0;
 uint64 SizeFound;
 int SizeIdx;
 bool bFound;
