 hardware->h_ifname);
 goto malformed;
 }
 switch (tlv_type) {
 case LLDP_TLV_END:
 if (tlv_size != 0) {
 log_warnx("lldp", "lldp end received with size not null on %s",
 hardware->h_ifname);
 goto malformed;
 }
 if (length)
 log_debug("lldp", "extra data after lldp end on %s",
 hardware->h_ifname);
 gotend = 1;
 break;
