 case LLDP_TLV_PORT_ID:
 CHECK_TLV_SIZE(2, "Port Id");
 tlv_subtype = PEEK_UINT8;
 if ((tlv_subtype == 0) || (tlv_subtype > 7)) {
 log_warnx("lldp", "unknown subtype for tlv id received on %s",
 hardware->h_ifname);
 goto malformed;
 }
