 hashtable_t* ref_table = NULL;
 struct serialize_s ser_s;
 uint8_t offset_size = 0;
 uint8_t ref_size = 0;
 uint64_t num_objects = 0;
 uint64_t root_object = 0;
 uint64_t offset_table_index = 0;
 bytearray_t *bplist_buff = NULL;
 uint64_t i = 0;
