 objects = ptr_array_new(256);
 //hashtable to write only once same nodes
 ref_table = hash_table_new(plist_data_hash, plist_data_compare, free);

 //serialize plist
 ser_s.objects = objects;
 ser_s.ref_table = ref_table;
