decodenetnum(
 const char *num,
 sockaddr_u *netnum
 )
{
 struct addrinfo hints, *ai = NULL;
 int err;
 u_short port;
 const char *cp;
 const char *port_str;
 char *pp;
 char *np;
 char name[80];

