 GuestFileRead *read_data = NULL;
 guchar *buf;
 FILE *fh;
 size_t read_count;

 if (!gfh) {
 return NULL;
 }

 if (!has_count) {
 count = QGA_READ_COUNT_DEFAULT;
 } else if (count < 0) {
 error_setg(errp, "value '%" PRId64 "' is invalid for argument count",
 count);
 return NULL;
 }

 fh = gfh->fh;

