 SHORTEST_LONG_RUN;

 if (symbol + runLen > static_cast<Int64>(maxSymbol + 1))
 {
 throw IEX_NAMESPACE::InputExc ("Error decoding Huffman table "
 "(Run beyond end of table).");
 }

 symbol += runLen - 1;

 }
